import { useState } from "react";
import "./index.css";

const initialTasks = [
  { id: 1, name: "Оновити ядро Arch Linux", completed: true },
  { id: 2, name: "Налаштувати кольори Waybar", completed: false },
  { id: 3, name: "Зробити бекап дотфайлів", completed: false },
];

export default function App() {
  const [tasks, setTasks] = useState(initialTasks);

  function ToggleTask(checkedId) {
    setTasks(
      tasks.map((task) =>
        task.id === checkedId ? { ...task, completed: !task.completed } : task,
      ),
    );
  }

  return (
    <div className="app-container">
      <h1>Менеджер завдань</h1>
      <div className="task-list">
        {tasks.map((task) => (
          <div
            className={`task ${task.completed ? "done" : "pending"}`}
            onClick={() => ToggleTask(task.id)}
            key={task.id}
          >
            <p>{task.name}</p>
          </div>
        ))}
      </div>
    </div>
  );
}
